    [Fact]
    public async Task GetItemQueryIterator_WithSelectManyJoin_FlattensArrays()
    {
        await SeedItems();
        var query = new QueryDefinition("SELECT VALUE t FROM c JOIN t IN c.tags");

        var iterator = _container.GetItemQueryIterator<string>(query);
