    {
        var container = new InMemoryContainer("subq-offset", "/pk");
        await container.CreateItemAsync(JObject.FromObject(new { id = "1", pk = "a", items = new[] { "a", "b", "c", "d", "e" } }), new PartitionKey("a"));

        var query = new QueryDefinition(
