        await _container.CreateItemAsync(JObject.FromObject(new { id = "2", partitionKey = "pk1", createdAt = "2024-06-15" }), new PartitionKey("pk1"));
        var results = await Query("SELECT * FROM c WHERE c.createdAt > '2024-03-01'");
