    {
        await SeedOne();
        var results = await RunQuery<long>("SELECT VALUE IntBitNot(0) FROM c");
        results.Should().ContainSingle().Which.Should().Be(-1L); // ~0 = -1
    }

    [Fact]
    public async Task IntBitNot_PositiveValue()
    {
        await SeedOne();
