    // ── A21: SQRT(0) = 0 ──
    [Fact]
    public async Task Sqrt_OfZero_ReturnsZero()
    {
        await Seed();
        var results = await RunQuery<double>(
            "SELECT VALUE SQRT(0) FROM c");
