    // ── A24: ARRAY_SLICE with negative start beyond length ──
    [Fact]
    public async Task ArraySlice_NegativeStartBeyondLength_ClampsToStart()
    {
        await Seed();
        // tags has 2 elements; -10 should clamp to index 0
