    [Fact]
    public async Task DateTimeFromParts_NullArgs_ReturnsUndefined()
    {
        await Seed();
        var results = await RunQuery<JToken>(
            "SELECT VALUE DateTimeFromParts(null, 1, 1) FROM c");
        results.Should().BeEmpty();
    }

