    [Fact]
    public async Task Subquery_EmptyArray_ReturnsEmptyArray()
    {
        await Seed();
        var r = await RunQuery<JToken>("SELECT VALUE ARRAY(SELECT VALUE x FROM x IN c.items WHERE x > 999) FROM c WHERE c.id = '1'");
