    {
        await _container.CreateItemAsync(
            JObject.Parse("""{"id":"1","pk":"p1","val":1}"""),
            new PartitionKey("p1"));
        await _container.CreateItemAsync(
            JObject.Parse("""{"id":"2","pk":"p1","val":null}"""),
            new PartitionKey("p1"));
        await _container.CreateItemAsync(
            JObject.Parse("""{"id":"3","pk":"p1"}"""),
