        r.Should().BeEmpty();
    }

    [Fact]
    public async Task Like_StringField_Works()
    {
        await Seed();
        var r = await RunQuery<JObject>("SELECT * FROM c WHERE c.status LIKE 'act%'");
        r.Should().ContainSingle();
    }
}

