    [Fact]
    public async Task NumberBin_NegativeValue_BinsCorrectly()
    {
        await _container.CreateItemStreamAsync(
            new MemoryStream(Encoding.UTF8.GetBytes("""{"id":"1","pk":"a","val":-7}""")),
            new PartitionKey("a"));

